const runId = $input.first().json.runId;
const brdModel = $input.first().json.brdModel || {};
const blueprint = $input.first().json.blueprint || {};

console.log(`[WF06][${runId}] Preparing gap analysis...`);

const canonicalSections = blueprint.canonicalSections || [
  'Executive Summary', 'Business Need', 'Scope', 'Stakeholders',
  'Functional Requirements', 'Non-Functional Requirements',
  'Integrations', 'Assumptions', 'Risks', 'Dependencies', 'Acceptance Criteria'
];

// Build a concise summary of what we found in the BRD model
const modelSummary = {
  hasProjectName: !!brdModel.projectName,
  hasBusinessProblem: !!brdModel.businessProblem,
  objectivesCount: (brdModel.objectives||[]).length,
  stakeholdersCount: (brdModel.stakeholders||[]).length,
  scopeInCount: (brdModel.scopeIn||[]).length,
  scopeOutCount: (brdModel.scopeOut||[]).length,
  frCount: (brdModel.functionalRequirements||[]).length,
  nfrCount: (brdModel.nonFunctionalRequirements||[]).length,
  risksCount: (brdModel.risks||[]).length,
  assumptionsCount: (brdModel.assumptions||[]).length,
  dependenciesCount: (brdModel.dependencies||[]).length,
  openQuestionsCount: (brdModel.openQuestions||[]).length,
  integrationsCount: (brdModel.integrationRequirements||[]).length
};

return [{
  json: {
    runId,
    brdModel,
    blueprint,
    source: $input.first().json.source,
    samples: $input.first().json.samples,
    options: $input.first().json.options,
    quality: $input.first().json.quality,
    gapPrompt: `You are a senior business analyst reviewing a Business Requirements Document for completeness.

BRD Model Summary (what was extracted from the source):
${JSON.stringify(modelSummary, null, 2)}

Full BRD Model:
${JSON.stringify(brdModel, null, 2).substring(0, 3000)}

Expected Canonical Sections from Sample Blueprint:
${canonicalSections.join(', ')}

Blueprint Style Rules:
${JSON.stringify(blueprint.styleRules || {}, null, 2)}

Task: Perform a comprehensive gap analysis and return ONLY valid JSON:

1. missingSections — sections in the blueprint not found or nearly empty in the BRD model
2. weakSections — sections present but needing significant expansion
3. missingRequirements — types of requirements that appear absent (e.g., "security NFRs", "performance SLAs")
4. recommendations — specific actionable recommendations to improve the BRD
5. sampleAlignmentGaps — things the sample expects that the source doesn't provide
6. coverageScore — 0.0-1.0 score of how complete the source BRD is vs the blueprint

Return valid JSON only:
{
  "missingSections": ["string"],
  "weakSections": ["string"],
  "missingRequirements": ["string"],
  "recommendations": ["string"],
  "sampleAlignmentGaps": ["string"],
  "coverageScore": 0.0
}`
  }
}];

const runId = $('Prepare Gap Analysis Prompt').first().json.runId;
const rawResponse = $input.first().json.text || $input.first().json.content || '';

console.log(`[WF06][${runId}] Parsing gap analysis...`);

let gapAnalysis;
try {
  const clean = rawResponse.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  gapAnalysis = JSON.parse(clean);
} catch(e) {
  console.warn(`[WF06][${runId}] Gap analysis parse failed, using defaults`);
  gapAnalysis = {
    missingSections: [],
    weakSections: [],
    missingRequirements: [],
    recommendations: ['Manual review recommended - gap analysis parsing failed'],
    sampleAlignmentGaps: [],
    coverageScore: 0.5
  };
}

console.log(`[WF06][${runId}] Gap analysis complete. Missing: ${(gapAnalysis.missingSections||[]).length}, Weak: ${(gapAnalysis.weakSections||[]).length}, Score: ${gapAnalysis.coverageScore}`);

return [{
  json: {
    runId,
    brdModel: $('Prepare Gap Analysis Prompt').first().json.brdModel,
    blueprint: $('Prepare Gap Analysis Prompt').first().json.blueprint,
    source: $('Prepare Gap Analysis Prompt').first().json.source,
    samples: $('Prepare Gap Analysis Prompt').first().json.samples,
    options: $('Prepare Gap Analysis Prompt').first().json.options,
    quality: $('Prepare Gap Analysis Prompt').first().json.quality,
    gapAnalysis
  }
}];
